#include <bits/stdc++.h>
using namespace std;

int n, m, l[1005][1005];
queue<pair<int, int> > q;

void BFS() {
    while (!q.empty()) {
        int x = q.front().first, 
            y = q.front().second;
        q.pop();
        int d[2][4] = {
            {0, 0, -1, 1},
            {-1, 1, 0, 0}
        };
        for (int i = 0; i < 4; i++) {
            int nx = x + d[0][i], 
                ny = y + d[1][i];
            if (nx >= 0 && nx <= m - 1) 
                if (ny >= 0 && ny <= n - 1) 
                    if (l[y][x] + 1 < l[ny][nx]) {
                        q.push(make_pair(nx, ny));
                        l[ny][nx] = l[y][x] + 1;
                    }
        }
    }
}

int main() {
    cin >> n >> m;
    for (int i = 0; i < n; i++) {
        getchar();
        for (int j = 0; j < m; j++) {
            int t;
            t = getchar() - '0';
            if (t) {
                l[i][j] = 0;
                q.push(make_pair(j, i));
            }
            else {
                l[i][j] = 2000;
            }
        }
    }
    BFS();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            cout << l[i][j] << ' ';
        }
        cout << endl;
    }
    return 0;
}
